const body = $json.body || $json;

// Aceita qualquer formato: (11) 90810-2064 | 11 90810-2064 | 11908102064
const rawPhone = String(body.telefone || '').trim();

if (!rawPhone) {
  throw new Error('Campo obrigatório ausente: telefone');
}

// Remove tudo que não for dígito para comparação
const digits = rawPhone.replace(/\D/g, '');

if (digits.length < 8) {
  throw new Error('Telefone inválido: ' + rawPhone);
}

// A query normaliza AMBOS os lados: tanto o buscado quanto o armazenado
// Isso garante match independente do formato salvo no banco
const sql = `
  SELECT
    id,
    telefone_candidato,
    tipo_avaliacao,
    export_date,
    resultado,
    criado_em
  FROM candidato_avaliacoes
  WHERE REGEXP_REPLACE(telefone_candidato, '[^0-9]', '', 'g') = '${digits}'
  ORDER BY criado_em DESC
  LIMIT 10
`;

return [{ json: { sql, telefone_original: rawPhone, digits } }];

const sqlNode = $('Normalizar Telefone e Montar SQL').first().json;
const rows    = $input.all().map(i => i.json).filter(r => r && r.id);

// Parse do campo resultado (JSON string → objeto)
const avaliacoes = rows.map(r => {
  let resultado = r.resultado;
  if (typeof resultado === 'string') {
    try { resultado = JSON.parse(resultado); } catch(e) { resultado = null; }
  }
  return {
    id:                  r.id,
    telefone_candidato:  r.telefone_candidato,
    tipo_avaliacao:      r.tipo_avaliacao,
    export_date:         r.export_date,
    criado_em:           r.criado_em,
    // Dados do participante extraídos do resultado
    participante:        resultado && resultado.participant ? resultado.participant : null,
    // Scores resumidos para exibição rápida
    scores:              resultado && resultado.scores     ? resultado.scores     : null,
    // Resultado completo (opcional — remova se quiser resposta menor)
    resultado
  };
});

return [{
  json: {
    telefone_buscado: sqlNode.telefone_original,
    total:            avaliacoes.length,
    avaliacoes
  }
}];
